<template>
	<view class="">
		<u-navbar title="卡密管理" :z-index="980" :custom-back="$util.back">
			<template #right>
				<view class="navbar-right">
					<view class="btn-item serch-btn" @click="handelFilterClick">
						<u-icon name="search"></u-icon>
						<text>筛选</text>
					</view>
					<view class="btn-item check-btn" @click="handelManagerClick">
						<u-icon name="list-dot"></u-icon>
						<text v-if="isManage">取消</text>
						<text v-else>管理</text>
					</view>
				</view>
			</template>
		</u-navbar>
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false"
			:style="{height:scrollHeight+'px'}" @scrolltolower="lower">
			<card-list :list="list" :selectedIds="selectedIds" :isManage="isManage"
				@selected-ids="handelSelectedIdsChange" @freeze="handelFreeze" @unfreeze="handelUnFreeze"
				@delete="handleDelete" @copy-link="handelCopyLink" />
			<u-loadmore :status="loading" icon-type="circle" @loadmore="fetchData" v-show="list.length" />
		</scroll-view>
		<view class="footer" v-if="isManage">
			<view class="wrap">
				<view class="checker" :class="{'checker-on':isSelectAll}" @click="handelAllSelected">
					<u-icon name="checkmark-circle" size="40"></u-icon>
				</view>
				<view class="btns">
					<view class="btn-item bg-blue" @click="handelFreeze()">冻结</view>
					<view class="btn-item bg-green" @click="handelUnFreeze()">解冻</view>
					<view class="btn-item bg-red" @click="handleDelete()">删除</view>
					<view class="btn-item bg-purple" @click="handelCopyCode()">复制卡密</view>
					<view class="btn-item bg-yellow" @click="handelCopyLink()">复制链接</view>
				</view>
			</view>
		</view>
		<card-filter ref="card-filter" @ok="handelFilterChange" />
		<!-- confirm 窗口 -->
		<u-modal v-model="showConfirm" content="确认删除吗？" show-cancel-button @confirm="doConfirm"></u-modal>
	</view>
</template>

<script>
	import CardList from './components/card-list'
	import CardFilter from './components/card-filter'
	export default {
		components: {
			'card-list': CardList,
			'card-filter': CardFilter,
		},
		data() {
			return {
				scrollHeight: 0,

				queryForm: {
					page: 1,
					limit: 20,
					keyword: '',
					keyword_type: '',
					create_time: '',
					expire_time: '',
					status: '', //1=未使用,2=已使用,3=已冻结,4=已过期
					batch_id: '', //卡组ID
					batch_log_id: '', //卡组生成日志ID
				},

				list: [], //卡组列表
				total: 0,
				loading: 'loadmore',
				url: '', //兑换网址

				isManage: false,
				isSelectAll: false,
				selectedIds: [],

				showConfirm: false,
				currItem: {},
			};
		},
		onReady() {
			this.$nextTick(() => {
				uni.createSelectorQuery().select(".scroll_content").boundingClientRect(res => {
					this.scrollHeight = this.deviceInfo.screenHeight - res.top
				}).exec()
			})
		},
		onLoad(e) {
			const {
				id
			} = e
			if (!id) {
				this.$util.msg('卡组id不能为空')
				setTimeout(() => {
					this.$util.back()
				}, 500)
				return
			}
			this.queryForm.batch_id = id
			this.fetchData()
		},
		onHide() {
			this.queryForm = this.$options.data().queryForm
		},
		methods: {
			// 复制
			paste(val) {
				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			async fetchData() {
				if (this.loading == 'nomore')
					return
				this.loading = 'loading'
				const {
					list,
					total,
					url
				} = await this.$u.api.goodsCardList(this.queryForm)
				this.total = total
				this.url = url
				if (list.length) {
					this.list = this.list.concat(list.map(item => {
						item._link = `${url}${item.code}`
						return item
					}))
				}
				if (list.length < this.queryForm.limit) {
					this.loading = 'nomore'
				} else {
					this.loading = 'loadmore'
				}
			},
			reloadData() {
				this.queryForm.page = 1
				this.loading = 'loadmore'
				this.list = []
				this.fetchData()
			},
			// 加载下一页
			lower() {
				if (this.loading == 'nomore')
					return
				this.queryForm.page++
				this.fetchData()
			},
			// 筛选点击
			handelFilterClick() {
				this.$refs['card-filter'].showEdit(this.queryForm)
			},
			// 筛选回调
			handelFilterChange(e) {
				this.queryForm = Object.assign({}, e)
				this.reloadData()
			},
			// 管理点击
			handelManagerClick() {
				this.isManage = !this.isManage
				this.isSelectAll = false
				this.selectedIds = []
			},
			// 全选
			handelAllSelected() {
				this.isSelectAll = !this.isSelectAll
				if (this.isSelectAll) {
					let ids = []
					this.list.map(item => {
						ids.push(item.id)
					})
					this.selectedIds = ids
				} else {
					this.selectedIds = []
				}
			},
			// 选中改变回调
			handelSelectedIdsChange({
				selectedIds,
				isSelectAll
			}) {
				this.selectedIds = selectedIds
				this.isSelectAll = isSelectAll
			},
			// 冻结点击
			handelFreeze(row) {
				if (row) {
					this.$u.throttle(async () => {
						await this.$u.api.goodsCardFreeze({
							freeze_type: 0,
							ids: row.id,
							type: 0,
						})
						this.$util.msg('操作成功')
						this.reloadData()
					}, 1000)
				} else {
					if (!this.selectedIds.length) {
						this.$util.msg('请选择数据')
						return
					}
					this.$u.throttle(async () => {
						await this.$u.api.goodsCardFreeze({
							freeze_type: 0,
							ids: this.selectedIds,
							type: 0,
						})
						this.selectedIds = []
						this.isSelectAll = false
						this.$util.msg('操作成功')
						this.reloadData()
					}, 1000)
				}
			},
			// 解冻点击
			handelUnFreeze(row) {
				if (row) {
					this.$u.throttle(async () => {
						await this.$u.api.goodsCardFreeze({
							freeze_type: 1,
							ids: row.id,
							type: 0,
						})
						this.$util.msg('操作成功')
						this.reloadData()
					}, 1000)
				} else {
					if (!this.selectedIds.length) {
						this.$util.msg('请选择数据')
						return
					}
					this.$u.throttle(async () => {
						await this.$u.api.goodsCardFreeze({
							freeze_type: 1,
							ids: this.selectedIds,
							type: 0,
						})
						this.selectedIds = []
						this.isSelectAll = false
						this.$util.msg('操作成功')
						this.reloadData()
					}, 1000)
				}
			},
			// 删除点击
			handleDelete(row) {
				if (row) {
					this.currItem = Object.assign({}, row)
				} else {
					if (!this.selectedIds.length) {
						this.$util.msg('请选择数据')
						return
					}
					this.currItem = {}
				}
				this.showConfirm = true
			},
			// 确认删除
			doConfirm() {
				if (this.currItem.id) {
					this.$u.throttle(async () => {
						await this.$u.api.goodsCardDelete({
							ids: this.currItem.id,
						})
						this.$util.msg('操作成功')
						this.reloadData()
					}, 1000)
				} else {
					this.$u.throttle(async () => {
						await this.$u.api.goodsCardDelete({
							ids: this.selectedIds,
						})
						this.selectedIds = []
						this.isSelectAll = false
						this.$util.msg('操作成功')
						this.reloadData()
					}, 1000)
				}
			},
			// 复制卡密
			handelCopyCode(row) {
				if (row) {
					this.paste(row.code)
				} else {
					if (!this.selectedIds.length) {
						this.$util.msg('请选择数据')
						return
					}
					let code_arr = []
					this.list.forEach(item => {
						if (this.selectedIds.includes(item.id))
							code_arr.push(item.code)
					})
					this.paste(code_arr.join('\n'))
					this.selectedIds = []
					this.isSelectAll = false
				}
			},
			// 复制链接点击
			handelCopyLink(row) {
				if (row) {
					this.paste(row._link)
				} else {
					if (!this.selectedIds.length) {
						this.$util.msg('请选择数据')
						return
					}
					let link_arr = []
					this.list.forEach(item => {
						if (this.selectedIds.includes(item.id))
							link_arr.push(item._link)
					})
					this.paste(link_arr.join('\n'))
					this.selectedIds = []
					this.isSelectAll = false
				}
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.uni-scroll-view-content {
			font-size: 26rpx;

			.code {
				font-size: 28rpx;
			}
		}
	}

	.serch-btn {
		padding: 3rpx 20rpx;
		background: #909399;
		border-radius: 44rpx;
		color: #fff;
		font-size: 26rpx;
	}

	.check-btn {
		padding: 3rpx 20rpx;
		background: linear-gradient(-90deg, #ff5c2d, #ff5c2d);
		border-radius: 44rpx;
		color: #fff;
		font-size: 26rpx;
	}

	.checker {
		color: #B0B0B0 !important;
	}

	.checker-on {
		color: #F05C02 !important;
	}

	.navbar-right {
		margin-right: 18rpx;
		display: flex;
		gap: 20rpx;

		.btn-item {
			white-space: nowrap;
		}

		.btn-item:active {
			opacity: .6;
		}
	}

	.footer {
		position: fixed;
		bottom: 0;
		z-index: 11;
		width: 100%;
		height: 104rpx;
		background-color: #fff;
		border-top: 1px solid #ccc;
		flex-wrap: nowrap;
		justify-content: space-between;
		align-items: center;
		display: flex;
		padding: 20rpx;

		.wrap {
			width: 100%;
			display: flex;
			align-items: center;

			.checker {}

			.btns {
				flex: 1;
				display: flex;
				gap: 10rpx;
				justify-content: flex-end;

				.btn-item {
					white-space: nowrap;
					border-radius: 26rpx;
					padding: 4rpx 22rpx;
					color: #fff;
					font-size: 26rpx;
				}

				.btn-item:active {
					opacity: .6;
				}
			}
		}
	}
</style>