<template>
	<view>
		<view class="list-box" v-if="list.length">
			<view class="list-item" v-for="item,index in list" :key="index" @click="handelItemClick(item)">
				<view class="top">
					<view v-show="isManage" class="checker" :class="{'checker-on':checkSelected(item.id)}"
						@click="handelChecker(item.id)">
						<u-icon name="checkmark-circle" size="30"></u-icon>
					</view>
					<view class="code" @click="paste(item.code)"><text>{{item.code}}</text><u-icon
							name="zhuanfa"></u-icon></view>
					<view class="status">
						<view class="status-item used" v-if="item.status == 2">已使用</view>
						<view class="status-item nouse" v-else-if="item.status == 1">未使用</view>
						<view class="status-item freez" v-else-if="item.status == 3">已冻结</view>
						<view class="status-item expire" v-else-if="item.status == 4">已过期</view>
					</view>
				</view>
				<view class="bottom">
					<view class="left">
						<view class="info">
							<text>创建时间：{{item.create_time}}</text>
							<text>过期时间：{{parseTime(item.expire_time)}}</text>
						</view>
						<view class="btns" v-show="!isManage">
							<view class="btn-item bg-green" @click="handelFreeze(item)" v-if="item.status==1">冻结</view>
							<view class="btn-item bg-green" @click="handelUnFreeze(item)" v-else-if="item.status==3">解冻
							</view>
							<view class="btn-item bg-blue" @click="handelLog(item)">日志</view>
							<view class="btn-item bg-yellow" @click="handleDelete(item)">删除</view>
							<view class="btn-item bg-red" @click="handelCopyLink(item)">复制链接</view>
						</view>
					</view>
					<view class="right">
						<view class="codeqr">
							<uqrcode :ref="'uqrcode'+index" :canvas-id="'qrcode'+index" :value="item._link" :size="100"
								:options="{}" @click="savePosterPath(index)">
								<template v-slot:h5save="{ tempFilePath }">
									<view
										style="display: flex;flex-direction: column;align-items: center;width: 160rpx;padding: 30px 0;background-color: #ffffff;">
										<text style="font-size: 14px;color: #9a9b9c;">若保存失败，请长按二维码进行保存</text>
										<image style="width: 160rpx;height: 160rpx;margin-top: 20px;"
											:src="tempFilePath">
										</image>
									</view>
								</template>
							</uqrcode>
						</view>
					</view>
				</view>
			</view>
		</view>		
		<template v-else>
			<view class="empty-data">
				<u-empty text="数据为空" mode="data"></u-empty>
			</view>
		</template>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			list: {
				type: Array,
				default: () => []
			},
			selectedIds: {
				type: Array,
				default: () => []
			},
			isManage: {
				type: Boolean,
				default: false,
			},
			url: {
				type: String,
				default: ''
			},
		},
		data() {
			return {
				currSelectedIds: [], //选中状态,
			};
		},
		computed: {

		},
		watch: {
			selectedIds: {
				handler(nv) {
					this.currSelectedIds = this.$u.deepClone(nv)
				},
				immediate: true,
			},
		},
		created() {

		},
		mounted() {

		},
		methods: {
			// 复制
			paste(val) {
				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			// 时间戳转日期
			parseTime(timestamp) {
				return this.$u.timeFormat(timestamp, 'yyyy-mm-dd hh:MM:ss')
			},
			// item点击
			handelItemClick(row) {
				// this.$emit('show-card', row)
			},			
			// 二维码点击
			savePosterPath(index) {
				this.$refs['uqrcode' + index][0].toTempFilePath({
					success: res => {
						uni.previewImage({
							current: 0, // 当前显示图片的索引值
							urls: [res.tempFilePath], // 需要预览的图片列表，photoList要求必须是数组
						})
					}
				})
			},
			// checker被点击
			handelChecker(cid) {
				let copy_ids = this.$u.deepClone(this.currSelectedIds)
				let index = copy_ids.findIndex(id => id == cid)
				if (index != -1) {
					copy_ids.splice(index, 1)
				} else {
					copy_ids.push(cid)
				}

				this.currSelectedIds = copy_ids
				this.$emit('selected-ids', {
					selectedIds: copy_ids,
					isSelectAll: this.checkAllSelected()
				})
			},
			// 判断是否已经选中
			checkSelected(cid) {
				let copy_ids = this.$u.deepClone(this.currSelectedIds)
				let flag = false
				let index = copy_ids.findIndex(id => id == cid)
				if (index == -1) {
					flag = false
				} else {
					flag = true
				}
				return flag
			},
			// 判断是否全部选中
			checkAllSelected() {
				if (this.list.length == this.currSelectedIds.length)
					return true
				else
					return false
			},
			// 冻结点击
			handelFreeze(row) {
				this.$emit('freeze',row)				
			},
			// 解冻点击
			handelUnFreeze(row) {
				this.$emit('unfreeze',row)		
			},
			// 日志点击
			handelLog(row) {
				this.$util.on(`/pages/ucenter_sub/exchange/card_log?id=${row.id}`)
			},
			// 删除点击
			handleDelete(row) {
				this.$emit('delete',row)				
			},
			// 复制链接点击
			handelCopyLink(row) {
				this.$emit('copy-link',row)	
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.checker {
		padding-right: 20rpx;
		color: #B0B0B0 !important;
	}

	.checker-on {
		color: #F05C02 !important;
	}

	.list-box {
		display: flex;
		flex-direction: column;
		gap: 10rpx;

		.list-item {
			position: relative;
			display: flex;
			flex-direction: column;
			gap: 20rpx;
			background-color: #fff;
			padding: 20rpx;
			cursor: pointer;

			.top {
				display: flex;
				align-items: center;

				.code {
					flex: 1;

					&>text {
						margin-right: 10rpx;
					}
				}

				.status {
					.status-item {
						border-radius: 20rpx;
						padding: 2rpx 20rpx;
						color: #fff;
					}

					.used {
						background-color: #03A251;
					}

					.nouse {
						background-color: #FF9901;
					}

					.freez {
						background-color: #FF9901;
					}

					.expire {
						background-color: #FF9901;
					}
				}
			}

			.bottom {
				display: flex;

				.left {
					flex: 1;
					display: flex;
					flex-direction: column;
					justify-content: space-between;

					.info {
						display: flex;
						flex-direction: column;
						gap: 5rpx;
						margin-bottom: 10rpx;

						text {
							color: #909399;
						}
					}

					.btns {
						display: flex;
						align-items: center;
						gap: 10rpx;

						.btn-item {
							border-radius: 20rpx;
							padding: 2rpx 20rpx;
							color: #fff;
							white-space: nowrap;
						}

						.btn-item:active {
							opacity: .6;
						}
					}
				}

				.right {}
			}
		}
	}
</style>